def get_proxy_ticket_for(self, service):
    if not settings.CAS_PROXY_CALLBACK:
        raise CasConfigException('No proxy callback set in settings')
    params = {'pgt': self.tgt, 'targetService': service}
    url = urljoin(settings.CAS_SERVER_URL, 'proxy') + '?' + urlencode(params)
    page = urlopen(url)
    try:
        response = page.read()
        tree = ElementTree.fromstring(response)
        if tree[0].tag.endswith('proxySuccess'):
            return tree[0][0].text
        else:
            logger.warning('Failed to get proxy ticket')
            raise CasTicketException('Failed to get proxy ticket: %s' % tree[0].text.strip())
    finally:
        page.close()

def diff_aff(self):
    row_degrees = np.array(self.kernel.sum(axis=1)).reshape(-1, 1)
    col_degrees = np.array(self.kernel.sum(axis=0)).reshape(1, -1)
    if sparse.issparse(self.kernel):
        return self.kernel.multiply(1 / np.sqrt(row_degrees)).multiply(1 / np.sqrt(col_degrees))
    else:
        return self.kernel / np.sqrt(row_degrees) / np.sqrt(col_degrees)

