def getch():
    if sys.platform in ['darwin', 'linux']:
        import termios
        import tty
        file_descriptor = sys.stdin.fileno()
        settings = termios.tcgetattr(file_descriptor)
        try:
            tty.setraw(file_descriptor)
            return sys.stdin.read(1)
        finally:
            termios.tcsetattr(file_descriptor, termios.TCSADRAIN, settings)
    elif sys.platform in ['cygwin', 'win32']:
        import msvcrt
        return msvcrt.getwch()

def rename_tables(db, table_mapping, reverse=False):
    from django.db import connection
    if reverse:
        table_mapping = [(dst, src) for (src, dst) in table_mapping]
    table_names = connection.introspection.table_names()
    for (source, destination) in table_mapping:
        if source in table_names and destination in table_names:
            print(u'    WARNING: not renaming {0} to {1}, because both tables already exist.'.format(source, destination))
        elif source in table_names and destination not in table_names:
            print(u'     - renaming {0} to {1}'.format(source, destination))
            db.rename_table(source, destination)

def generous_parse_uri(uri):
    parse_result = urlparse(uri)
    if parse_result.scheme == '':
        abspath = os.path.abspath(parse_result.path)
        if IS_WINDOWS:
            abspath = windows_to_unix_path(abspath)
        fixed_uri = 'file://{}'.format(abspath)
        parse_result = urlparse(fixed_uri)
    return parse_result

def collect(self):
    for (root, dirname, files) in walk(self.migration_home):
        for file_name in file_filter(files, '*.py'):
            file_name = file_name.replace('.py', '')
            file = None
            try:
                if file_name == '__init__':
                    continue
                (file, pathname, description) = find_module(file_name, [root])
                load_module(file_name, file, pathname, description)
            finally:
                if file is not None:
                    file.close()

def transition(field, source='*', target=None, on_error=None, conditions=[], permission=None, custom={}):

    def inner_transition(func):
        (wrapper_installed, fsm_meta) = (True, getattr(func, '_django_fsm', None))
        if not fsm_meta:
            wrapper_installed = False
            fsm_meta = FSMMeta(field=field, method=func)
            setattr(func, '_django_fsm', fsm_meta)
        if isinstance(source, (list, tuple, set)):
            for state in source:
                func._django_fsm.add_transition(func, state, target, on_error, conditions, permission, custom)
        else:
            func._django_fsm.add_transition(func, source, target, on_error, conditions, permission, custom)

        @wraps(func)
        def _change_state(instance, *args, **kwargs):
            return fsm_meta.field.change_state(instance, func, *args, **kwargs)
        if not wrapper_installed:
            return _change_state
        return func
    return inner_transition

def get_elapsed_time(self):
    if self._start_time is None or self._end_time is not None:
        return self._elapsed_time
    return self._elapsed_time + (datetime.datetime.now() - self._start_time)

def get_file_contents(source_path: str) -> str:
    open_funcs = [functools.partial(codecs.open, source_path, encoding='utf-8'), functools.partial(open, source_path, 'r')]
    for open_func in open_funcs:
        try:
            with open_func() as f:
                return f.read()
        except Exception:
            pass
    return 'raise IOError("Unable to load step file at: {}")'.format(source_path)

def get_proxy_ticket_for(self, service):
    if not settings.CAS_PROXY_CALLBACK:
        raise CasConfigException('No proxy callback set in settings')
    params = {'pgt': self.tgt, 'targetService': service}
    url = urljoin(settings.CAS_SERVER_URL, 'proxy') + '?' + urlencode(params)
    page = urlopen(url)
    try:
        response = page.read()
        tree = ElementTree.fromstring(response)
        if tree[0].tag.endswith('proxySuccess'):
            return tree[0][0].text
        else:
            logger.warning('Failed to get proxy ticket')
            raise CasTicketException('Failed to get proxy ticket: %s' % tree[0].text.strip())
    finally:
        page.close()

def diff_aff(self):
    row_degrees = np.array(self.kernel.sum(axis=1)).reshape(-1, 1)
    col_degrees = np.array(self.kernel.sum(axis=0)).reshape(1, -1)
    if sparse.issparse(self.kernel):
        return self.kernel.multiply(1 / np.sqrt(row_degrees)).multiply(1 / np.sqrt(col_degrees))
    else:
        return self.kernel / np.sqrt(row_degrees) / np.sqrt(col_degrees)

def template_to_base_path(template, google_songs):
    if template == os.getcwd() or template == '%suggested%':
        base_path = os.getcwd()
    else:
        template = os.path.abspath(template)
        song_paths = [template_to_filepath(template, song) for song in google_songs]
        base_path = os.path.dirname(os.path.commonprefix(song_paths))
    return base_path

def _begin(self, connection, filterargs=(), escape=True):
    if escape:
        filterargs = self._escape_filterargs(filterargs)
    try:
        filterstr = self.filterstr % filterargs
        msgid = connection.search(force_str(self.base_dn), self.scope, force_str(filterstr))
    except ldap.LDAPError as e:
        msgid = None
        logger.error(u"search('%s', %d, '%s') raised %s" % (self.base_dn, self.scope, filterstr, pprint.pformat(e)))
    return msgid

def get_imports(self, option):
    if option:
        if len(option) == 1 and option[0].isupper() and (len(option[0]) > 3):
            return getattr(settings, option[0])
        else:
            codes = [e for e in option if e.isupper() and len(e) == 3]
            if len(codes) != len(option):
                raise ImproperlyConfigured('Invalid currency codes found: %s' % codes)
            return codes
    for attr in ('CURRENCIES', 'SHOP_CURRENCIES'):
        try:
            return getattr(settings, attr)
        except AttributeError:
            continue
    return option

