def debug_generate(self, debug_generator, *gen_args, **gen_kwargs):
    if self.isEnabledFor(logging.DEBUG):
        message = debug_generator(*gen_args, **gen_kwargs)
        if message is not None:
            return self.debug(message)

def prefer_replica(nodes: List[DiscoveredNode]) -> Optional[DiscoveredNode]:
    masters = [node for node in nodes if node.state == NodeState.Master]
    replicas = [node for node in nodes if node.state != NodeState.Master]
    if replicas:
        return random.choice(replicas)
    else:
        return masters[0]

def action_draft(self):
    for rec in self:
        if not rec.state == 'cancelled':
            raise UserError(_('You need to cancel it before reopening.'))
        if not (rec.am_i_owner or rec.am_i_approver):
            raise UserError(_('You are not authorized to do this.\r\nOnly owners or approvers can reopen Change Requests.'))
        rec.write({'state': 'draft'})

