def _check_inclusions(self, f, domains=None):
    filename = f if isinstance(f, six.string_types) else f.path
    if domains is None:
        domains = list(self.domains.values())
    domains = list(domains)
    domains.insert(0, self)
    for dom in domains:
        if dom.include:
            for regex in dom.include:
                if re.search(regex, filename):
                    return True
            return False
        else:
            for regex in dom.exclude:
                if re.search(regex, filename, flags=re.UNICODE):
                    return False
    return True

def _read_socket(self):
    while True:
        base_bytes = self._socket.recv(BASE_SIZE)
        base = basemessage.parse(base_bytes)
        payload_bytes = self._socket.recv(base.payload_length)
        self._handle_message(packet.parse(base_bytes + payload_bytes))

def all_nodes_that_receive(service, service_configuration=None, run_only=False, deploy_to_only=False):
    assert not (run_only and deploy_to_only)
    if service_configuration is None:
        service_configuration = read_services_configuration()
    runs_on = service_configuration[service]['runs_on']
    deployed_to = service_configuration[service].get('deployed_to')
    if deployed_to is None:
        deployed_to = []
    if run_only:
        result = runs_on
    elif deploy_to_only:
        result = deployed_to
    else:
        result = set(runs_on) | set(deployed_to)
    return list(sorted(result))

