def load(self, url, offset, length):
    headers = {}
    if offset != 0 or length != -1:
        headers['Range'] = BlockLoader._make_range_header(offset, length)
    if self.cookie_maker:
        if isinstance(self.cookie_maker, six.string_types):
            headers['Cookie'] = self.cookie_maker
        else:
            headers['Cookie'] = self.cookie_maker.make()
    if not self.session:
        self.session = requests.Session()
    r = self.session.get(url, headers=headers, stream=True)
    r.raise_for_status()
    return r.raw

def evaluate_inline(self, groups):
    if self.lines:
        if self.group_comments and self.line_num == self.prev_line + 1 and (groups['leading_space'] == self.leading):
            self.line_comments[-1][0] += '\n' + groups['line'][2:].replace('\\\n', '')
        else:
            self.line_comments.append([groups['line'][2:].replace('\\\n', ''), self.line_num, self.current_encoding])
        self.leading = groups['leading_space']
        self.prev_line = self.line_num

def nullity_sort(df, sort=None):
    if sort == 'ascending':
        return df.iloc[np.argsort(df.count(axis='columns').values), :]
    elif sort == 'descending':
        return df.iloc[np.flipud(np.argsort(df.count(axis='columns').values)), :]
    else:
        return df

def get_grid(start, end, nsteps=100):
    step = (end - start) / float(nsteps)
    return [start + i * step for i in xrange(nsteps + 1)]

def _exponential_kamb(cos_dist, sigma=3):
    n = float(cos_dist.size)
    f = 2 * (1.0 + n / sigma ** 2)
    count = np.exp(f * (cos_dist - 1))
    units = np.sqrt(n * (f / 2.0 - 1) / f ** 2)
    return (count, units)

