def _prohibited(from_op, to_op):
    if from_op is UnaryOperators.Not:
        if to_op is not UnaryOperators.Nothing:
            return True
    if from_op is UnaryOperators.UAdd:
        if to_op is UnaryOperators.Nothing:
            return True
