def clusters(self):
    if not hasattr(self, '_clusters'):
        cs = {}
        for cr in self.doc['clusters']:
            cs[cr['name']] = c = copy.deepcopy(cr['cluster'])
            if 'server' not in c:
                c['server'] = 'http://localhost'
            BytesOrFile.maybe_set(c, 'certificate-authority')
        self._clusters = cs
    return self._clusters
